-- Property & Garage Management System — SQLite Schema
-- This migration runs once automatically when the app launches via tauri-plugin-sql.
-- All tables use TEXT primary keys (UUIDs generated by the JS layer via crypto.randomUUID()).
-- Seed data is included so the app starts with demo data on first launch.

PRAGMA foreign_keys = ON;

-- ──────────────────────────────────────────
-- MARKETS
-- ──────────────────────────────────────────
CREATE TABLE IF NOT EXISTS markets (
  id           TEXT PRIMARY KEY,
  name         TEXT NOT NULL,
  phone_number TEXT NOT NULL,
  monthly_rent INTEGER NOT NULL DEFAULT 0,
  address      TEXT,
  created_at   TEXT NOT NULL DEFAULT (date('now'))
);

-- ──────────────────────────────────────────
-- SHOPS
-- ──────────────────────────────────────────
CREATE TABLE IF NOT EXISTS shops (
  id             TEXT PRIMARY KEY,
  market_id      TEXT NOT NULL REFERENCES markets(id) ON DELETE CASCADE,
  shop_name      TEXT NOT NULL,
  tenant_name    TEXT NOT NULL,
  phone_number   TEXT NOT NULL,
  monthly_rent   INTEGER NOT NULL DEFAULT 0,
  paid_rent      INTEGER NOT NULL DEFAULT 0,
  current_due    INTEGER NOT NULL DEFAULT 0,
  due_date       TEXT NOT NULL DEFAULT '',
  payment_status TEXT NOT NULL DEFAULT 'Due'
                 CHECK (payment_status IN ('Paid', 'Due')),
  shop_type      TEXT NOT NULL DEFAULT 'Rented'
                 CHECK (shop_type IN ('Rented', 'Leased')),
  start_date     TEXT NOT NULL DEFAULT '',
  end_date       TEXT NOT NULL DEFAULT ''
);

CREATE INDEX IF NOT EXISTS shops_market_id_idx      ON shops(market_id);
CREATE INDEX IF NOT EXISTS shops_payment_status_idx ON shops(payment_status);

-- ──────────────────────────────────────────
-- GARAGES
-- ──────────────────────────────────────────
CREATE TABLE IF NOT EXISTS garages (
  id             TEXT PRIMARY KEY,
  garage_no      TEXT NOT NULL UNIQUE,
  owner_name     TEXT NOT NULL,
  mobile_number  TEXT NOT NULL,
  vehicle_number TEXT NOT NULL,
  vehicle_type   TEXT NOT NULL DEFAULT 'Car'
                 CHECK (vehicle_type IN ('Car', 'Bike', 'Truck', 'Other')),
  monthly_rent   INTEGER NOT NULL DEFAULT 0,
  payment_status TEXT NOT NULL DEFAULT 'Due'
                 CHECK (payment_status IN ('Paid', 'Due')),
  current_due    INTEGER NOT NULL DEFAULT 0,
  lease_end_date TEXT NOT NULL DEFAULT '',
  lease_type     TEXT NOT NULL DEFAULT 'Monthly'
                 CHECK (lease_type IN ('Monthly', 'Yearly', 'Long-term')),
  address        TEXT,
  start_date     TEXT NOT NULL DEFAULT ''
);

CREATE INDEX IF NOT EXISTS garages_payment_status_idx ON garages(payment_status);

-- ──────────────────────────────────────────
-- PAYMENTS
-- ──────────────────────────────────────────
CREATE TABLE IF NOT EXISTS payments (
  id           TEXT PRIMARY KEY,
  payment_date TEXT NOT NULL,
  name         TEXT NOT NULL,
  payment_type TEXT NOT NULL CHECK (payment_type IN ('Shop', 'Garage')),
  amount       INTEGER NOT NULL DEFAULT 0,
  reference    TEXT NOT NULL DEFAULT '',
  created_at   TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE INDEX IF NOT EXISTS payments_date_idx ON payments(payment_date DESC);

-- ──────────────────────────────────────────
-- BACKUPS
-- ──────────────────────────────────────────
CREATE TABLE IF NOT EXISTS backups (
  id               TEXT PRIMARY KEY,
  name             TEXT NOT NULL,
  description      TEXT NOT NULL DEFAULT '',
  backup_type      TEXT NOT NULL DEFAULT 'Full Backup'
                   CHECK (backup_type IN ('Full Backup', 'Incremental')),
  created_at_label TEXT NOT NULL DEFAULT '',
  size_label       TEXT NOT NULL DEFAULT '',
  created_by       TEXT NOT NULL DEFAULT 'Admin',
  created_at       TEXT NOT NULL DEFAULT (datetime('now'))
);

